__kernel void likelihood_kernel(__global double* arrayX, __global double* arrayY, __global double* xj, __global double* yj,
                                __global double* CDF, __global int* ind, __global int* objxy, __global double* likelihood,
                                __global unsigned char* I, __global double* u, __global double* weights,
                                int Nparticles, int countOnes, int max_size, int k, int IszY, int Nfr,
                                __global int* seed, __global double* partial_sums, __local double* local_sum) {
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    int local_id = get_local_id(0);
    local_sum[local_id] = 0.0;

    // Update positions with noise
    double rand_val_x = 0.0;
    double rand_val_y = 0.0;

    // Simple RNG approximation for OpenCL (using seed array)
    int num = 1103515245 * seed[x] + 12345;
    seed[x] = num % 2147483647;
    double u_val = fabs(seed[x] / ((double) 2147483647));

    num = 1103515245 * seed[x] + 12345;
    seed[x] = num % 2147483647;
    double v_val = fabs(seed[x] / ((double) 2147483647));

    rand_val_x = sqrt(-2.0 * log(u_val)) * cos(2.0 * 3.1415926535897932 * v_val);

    num = 1103515245 * seed[x] + 12345;
    seed[x] = num % 2147483647;
    u_val = fabs(seed[x] / ((double) 2147483647));

    num = 1103515245 * seed[x] + 12345;
    seed[x] = num % 2147483647;
    v_val = fabs(seed[x] / ((double) 2147483647));

    rand_val_y = sqrt(-2.0 * log(u_val)) * cos(2.0 * 3.1415926535897932 * v_val);

    arrayX[x] += 1.0 + 5.0 * rand_val_x;
    arrayY[x] += -2.0 + 2.0 * rand_val_y;

    // Calculate likelihood
    double likelihood_sum = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)(arrayX[x] + 0.5) + objxy[y * 2 + 1];
        int indY = (int)(arrayY[x] + 0.5) + objxy[y * 2];
        int index = indX * IszY * Nfr + indY * Nfr + k;
        if (index >= max_size) index = 0;
        if (index < 0) index = 0;

        int val = I[index];
        likelihood_sum += ((pow((val - 100), 2) - pow((val - 228), 2)) / 50.0);
    }
    likelihood[x] = likelihood_sum / ((double) countOnes);

    // Update weights
    weights[x] = weights[x] * exp(likelihood[x]);
    local_sum[local_id] = weights[x];

    // Barrier for local sum
    barrier(CLK_LOCAL_MEM_FENCE);

    // Parallel sum within block (simple reduction)
    for (int s = 1; s < get_local_size(0); s *= 2) {
        if (local_id % (2 * s) == 0) {
            if (local_id + s < get_local_size(0)) {
                local_sum[local_id] += local_sum[local_id + s];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (local_id == 0) {
        partial_sums[x] = local_sum[0];
    }
}

__kernel void sum_kernel(__global double* partial_sums, int Nparticles) {
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    // This kernel is simplified; full reduction would require more complex logic
    // Here we just ensure partial_sums is ready for normalization
    if (x == 0) {
        double total = 0.0;
        for (int i = 0; i < Nparticles; i++) {
            total += partial_sums[i];
        }
        partial_sums[0] = total;
    }
}

__kernel void normalize_weights_kernel(__global double* weights, int Nparticles, __global double* partial_sums, 
                                       __global double* CDF, __global double* u, __global int* seed) {
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    double sumWeights = partial_sums[0];
    weights[x] = weights[x] / sumWeights;

    // Build CDF
    if (x == 0) {
        CDF[0] = weights[0];
    } else {
        CDF[x] = weights[x] + CDF[x-1];
    }

    // Generate u values
    if (x == 0) {
        int num = 1103515245 * seed[0] + 12345;
        seed[0] = num % 2147483647;
        double u1 = fabs(seed[0] / ((double) 2147483647));
        u1 = (1.0 / ((double) Nparticles)) * u1;

        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + ((double)i / ((double) Nparticles));
        }
    }
}

__kernel void find_index_kernel(__global double* arrayX, __global double* arrayY, __global double* CDF, 
                                __global double* u, __global double* xj, __global double* yj, 
                                __global double* weights, int Nparticles) {
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    double value = u[j];
    int index = -1;

    // Binary search for index
    int beginIndex = 0;
    int endIndex = Nparticles - 1;

    while (beginIndex <= endIndex) {
        int middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (CDF[middleIndex] >= value) {
            if (middleIndex == 0 || CDF[middleIndex - 1] < value) {
                index = middleIndex;
                break;
            } else {
                endIndex = middleIndex - 1;
            }
        } else {
            beginIndex = middleIndex + 1;
        }
    }

    if (index == -1) {
        index = Nparticles - 1;
    }

    xj[j] = arrayX[index];
    yj[j] = arrayY[index];

    // Reset for next iteration
    arrayX[j] = xj[j];
    arrayY[j] = yj[j];
    weights[j] = 1.0 / ((double) Nparticles);
}
